-- 部门表
DROP TABLE IF EXISTS department;
CREATE TABLE department (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    name VARCHAR(50) NOT NULL,
    parent_id INTEGER DEFAULT 0,
    create_time DATETIME DEFAULT CURRENT_TIMESTAMP
);

-- 用户表
DROP TABLE IF EXISTS sys_user;
CREATE TABLE sys_user (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    username VARCHAR(50) NOT NULL UNIQUE,
    password VARCHAR(100) NOT NULL,
    real_name VARCHAR(50) NOT NULL,
    email VARCHAR(100),
    phone VARCHAR(20),
    dept_id INTEGER,
    position VARCHAR(50),
    role VARCHAR(20) DEFAULT 'USER',
    status INTEGER DEFAULT 1,
    create_time DATETIME DEFAULT CURRENT_TIMESTAMP,
    FOREIGN KEY (dept_id) REFERENCES department(id)
);

-- 通知公告表
DROP TABLE IF EXISTS notice;
CREATE TABLE notice (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    title VARCHAR(200) NOT NULL,
    content TEXT,
    author_id INTEGER,
    create_time DATETIME DEFAULT CURRENT_TIMESTAMP,
    update_time DATETIME DEFAULT CURRENT_TIMESTAMP,
    FOREIGN KEY (author_id) REFERENCES sys_user(id)
);

-- 审批类型表
DROP TABLE IF EXISTS approval_type;
CREATE TABLE approval_type (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    name VARCHAR(50) NOT NULL,
    description VARCHAR(200)
);

-- 审批申请表
DROP TABLE IF EXISTS approval;
CREATE TABLE approval (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    type_id INTEGER NOT NULL,
    user_id INTEGER NOT NULL,
    title VARCHAR(200) NOT NULL,
    content TEXT,
    status INTEGER DEFAULT 0,
    create_time DATETIME DEFAULT CURRENT_TIMESTAMP,
    update_time DATETIME DEFAULT CURRENT_TIMESTAMP,
    FOREIGN KEY (type_id) REFERENCES approval_type(id),
    FOREIGN KEY (user_id) REFERENCES sys_user(id)
);

-- 审批记录表
DROP TABLE IF EXISTS approval_record;
CREATE TABLE approval_record (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    approval_id INTEGER NOT NULL,
    approver_id INTEGER NOT NULL,
    result INTEGER NOT NULL,
    comment TEXT,
    create_time DATETIME DEFAULT CURRENT_TIMESTAMP,
    FOREIGN KEY (approval_id) REFERENCES approval(id),
    FOREIGN KEY (approver_id) REFERENCES sys_user(id)
);

-- 日程表
DROP TABLE IF EXISTS schedule;
CREATE TABLE schedule (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    user_id INTEGER NOT NULL,
    title VARCHAR(200) NOT NULL,
    content TEXT,
    start_time DATETIME NOT NULL,
    end_time DATETIME NOT NULL,
    create_time DATETIME DEFAULT CURRENT_TIMESTAMP,
    FOREIGN KEY (user_id) REFERENCES sys_user(id)
);

-- 考勤记录表
DROP TABLE IF EXISTS attendance;
CREATE TABLE attendance (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    user_id INTEGER NOT NULL,
    type INTEGER NOT NULL,
    create_time DATETIME DEFAULT CURRENT_TIMESTAMP,
    FOREIGN KEY (user_id) REFERENCES sys_user(id)
);

-- 客户表
DROP TABLE IF EXISTS customer;
CREATE TABLE customer (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    name VARCHAR(100) NOT NULL,
    contact VARCHAR(50),
    phone VARCHAR(20),
    address VARCHAR(200),
    status INTEGER DEFAULT 1,
    create_time DATETIME DEFAULT CURRENT_TIMESTAMP
);

-- 产品表
DROP TABLE IF EXISTS product;
CREATE TABLE product (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    name VARCHAR(100) NOT NULL,
    code VARCHAR(50) NOT NULL UNIQUE,
    price DECIMAL(10,2) NOT NULL,
    stock INTEGER DEFAULT 0,
    unit VARCHAR(20) DEFAULT '件',
    status INTEGER DEFAULT 1,
    create_time DATETIME DEFAULT CURRENT_TIMESTAMP
);

-- 销售订单表
DROP TABLE IF EXISTS sales_order;
CREATE TABLE sales_order (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    order_no VARCHAR(50) NOT NULL UNIQUE,
    customer_id INTEGER NOT NULL,
    user_id INTEGER NOT NULL,
    total_amount DECIMAL(12,2) DEFAULT 0,
    status INTEGER DEFAULT 0,
    create_time DATETIME DEFAULT CURRENT_TIMESTAMP,
    FOREIGN KEY (customer_id) REFERENCES customer(id),
    FOREIGN KEY (user_id) REFERENCES sys_user(id)
);

-- 销售订单明细表
DROP TABLE IF EXISTS sales_order_item;
CREATE TABLE sales_order_item (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    order_id INTEGER NOT NULL,
    product_id INTEGER NOT NULL,
    price DECIMAL(10,2) NOT NULL,
    quantity INTEGER NOT NULL,
    subtotal DECIMAL(12,2) NOT NULL,
    FOREIGN KEY (order_id) REFERENCES sales_order(id),
    FOREIGN KEY (product_id) REFERENCES product(id)
);

-- =============================================
-- 会计凭证管理模块
-- =============================================

-- 会计科目表
DROP TABLE IF EXISTS account_subject;
CREATE TABLE account_subject (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    subject_code VARCHAR(20) NOT NULL UNIQUE,
    subject_name VARCHAR(100) NOT NULL,
    parent_id INTEGER DEFAULT 0,
    balance_direction VARCHAR(1) NOT NULL,
    level INTEGER DEFAULT 1,
    is_leaf INTEGER DEFAULT 1,
    status INTEGER DEFAULT 1,
    create_time DATETIME DEFAULT CURRENT_TIMESTAMP,
    update_time DATETIME DEFAULT CURRENT_TIMESTAMP
);

-- 凭证主表
DROP TABLE IF EXISTS voucher;
CREATE TABLE voucher (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    voucher_no VARCHAR(50) NOT NULL UNIQUE,
    voucher_date DATE NOT NULL,
    attachment_count INTEGER DEFAULT 0,
    audit_status INTEGER DEFAULT 0,
    posting_status INTEGER DEFAULT 0,
    maker_id INTEGER,
    checker_id INTEGER,
    poster_id INTEGER,
    total_amount DECIMAL(15,2) DEFAULT 0,
    remark TEXT,
    create_time DATETIME DEFAULT CURRENT_TIMESTAMP,
    update_time DATETIME,
    FOREIGN KEY (maker_id) REFERENCES sys_user(id),
    FOREIGN KEY (checker_id) REFERENCES sys_user(id),
    FOREIGN KEY (poster_id) REFERENCES sys_user(id)
);

-- 凭证明细表
DROP TABLE IF EXISTS voucher_item;
CREATE TABLE voucher_item (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    voucher_id INTEGER NOT NULL,
    subject_id INTEGER NOT NULL,
    direction VARCHAR(1) NOT NULL,
    amount DECIMAL(15,2) NOT NULL,
    summary VARCHAR(200),
    seq INTEGER DEFAULT 1,
    FOREIGN KEY (voucher_id) REFERENCES voucher(id),
    FOREIGN KEY (subject_id) REFERENCES account_subject(id)
);


-- 凭证明细表
-- 每个凭证2条明细（借贷平衡）

SELECT
    v.id,
    CASE (v.id % 12)
        WHEN 0 THEN 1
        WHEN 1 THEN 2
        WHEN 2 THEN 3
        WHEN 3 THEN 6
        WHEN 4 THEN 7
        WHEN 5 THEN 12
        WHEN 6 THEN 14
        WHEN 7 THEN 18
        WHEN 8 THEN 19
        WHEN 9 THEN 21
        WHEN 10 THEN 22
        WHEN 11 THEN 23
    END,
    '1',
    v.total_amount,
    v.remark,
    1
FROM voucher v;

-- 贷方分录
SELECT
    v.id,
    CASE (v.id % 12)
        WHEN 0 THEN 2
        WHEN 1 THEN 1
        WHEN 2 THEN 20
        WHEN 3 THEN 20
        WHEN 4 THEN 20
        WHEN 5 THEN 20
        WHEN 6 THEN 20
        WHEN 7 THEN 20
        WHEN 8 THEN 20
        WHEN 9 THEN 20
        WHEN 10 THEN 20
        WHEN 11 THEN 20
    END,
    '2',
    v.total_amount,
    v.remark,
    2
FROM voucher v;
